use strict;
use warnings;

my $filename = shift || die "Usage: $0 <filename>\n";
open(my $fh, '<', $filename) or die "Cannot open file '$filename': $!";

my %word_counts;
while (my $line = <$fh>) {
    chomp $line;
    my @words = split(/\s+/, lc($line));
    foreach my $word (@words) {
        next if $word =~ /^\s*$/;  # Skip empty strings
        $word_counts{$word}++;
    }
}

close($fh);

my @sorted_words = sort { $word_counts{$b} <=> $word_counts{$a} } keys %word_counts;
@sorted_words = @sorted_words[0..2];  # Take top 3

foreach my $word (@sorted_words) {
    print "$word: $word_counts{$word}\n";
}

